body.script:
(function(){
  var n=document.querySelector('.nav');
  window.addEventListener('scroll',function(){n.classList.toggle('stuck',window.scrollY>60)});

  var b=document.getElementById('burger'),m=document.getElementById('navMenu');
  b.addEventListener('click',function(){b.classList.toggle('on');m.classList.toggle('open');b.setAttribute('aria-expanded',b.classList.contains('on'))});
  var lk=m.querySelectorAll('a');
  for(var i=0;i<lk.length;i++){lk[i].addEventListener('click',function(){b.classList.remove('on');m.classList.remove('open');b.setAttribute('aria-expanded','false')})}

  var o=new IntersectionObserver(function(entries){entries.forEach(function(e){if(e.isIntersecting){e.target.classList.add('vis');o.unobserve(e.target)}})},{threshold:.08,rootMargin:'0px 0px -40px 0px'});
  var els=document.querySelectorAll('.rv');
  for(var j=0;j<els.length;j++){o.observe(els[j])}

  var fqs=document.querySelectorAll('.fq');
  for(var k=0;k<fqs.length;k++){fqs[k].addEventListener('click',function(){var it=this.parentElement,wo=it.classList.contains('open');var all=document.querySelectorAll('.fi-card.open');for(var x=0;x<all.length;x++){all[x].classList.remove('open');all[x].querySelector('.fq').setAttribute('aria-expanded','false')}if(!wo){it.classList.add('open');this.setAttribute('aria-expanded','true')}})}

  // Lightbox
  var lb=document.getElementById('lightbox'),lbi=document.getElementById('lbImg'),lbc=document.getElementById('lbClose');
  var gis=document.querySelectorAll('.gi img');
  for(var g=0;g<gis.length;g++){gis[g].addEventListener('click',function(){lbi.src=this.src;lbi.alt=this.alt;lb.classList.add('active');document.body.style.overflow='hidden'})}
  lb.addEventListener('click',function(e){if(e.target===lb||e.target===lbc){lb.classList.remove('active');document.body.style.overflow=''}});
  lbc.addEventListener('click',function(){lb.classList.remove('active');document.body.style.overflow=''});
  document.addEventListener('keydown',function(e){if(e.key==='Escape'){lb.classList.remove('active');document.body.style.overflow=''}});
})();
